arguments.argument:
if global.gamePaused=false
{
  if autoMove=1 //Auto move left and right
  {
    if moveProg=0
    {
      x+=moveSpd
      if x>rightEnd {moveProg=1}
    }
    else if moveProg=1
    {
      x-=moveSpd
      if x<leftEnd {moveProg=0}
    }
  }
  else if autoMove=2 //Auto move up and down
  {
    if moveProg=0
    {
      y+=moveSpd
      if y>rightEnd {moveProg=1}
    }
    else if moveProg=1
    {
      y-=moveSpd
      if y<leftEnd {moveProg=0}
    }
  }
}
